svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
var svg       = document.getElementById('root');
  var dataLayerEl = document.getElementById('data-layer');
  var edgeLayer = document.getElementById('edge-layer');
  var nodeLayer = document.getElementById('node-layer');

  /* §2 isDark before all build code */

  /* ── DATA ─────────────────────────────────────────────────────────────
     cluster: 1=Frontend 2=Backend 3=Data 4=Infra 5=Auth
     x,y: hand-positioned within plot area (68–850 × 100–500)
     r: node radius — encodes degree (connections), set after edges counted  */
  var nodes = [
    /* Frontend cluster — left-centre */
    { id:'web-app',   label:'Web App',     cluster:1, x:148, y:220 },
    { id:'mobile',    label:'Mobile',      cluster:1, x:148, y:360 },
    { id:'cdn',       label:'CDN',         cluster:1, x:220, y:290 },

    /* Backend cluster — centre */
    { id:'api-gw',    label:'API GW',      cluster:2, x:360, y:210 },
    { id:'user-svc',  label:'User Svc',    cluster:2, x:360, y:300 },
    { id:'order-svc', label:'Order Svc',   cluster:2, x:360, y:390 },
    { id:'notify',    label:'Notify',      cluster:2, x:460, y:450 },

    /* Data cluster — right-centre */
    { id:'postgres',  label:'Postgres',    cluster:3, x:530, y:290 },
    { id:'redis',     label:'Redis',       cluster:3, x:530, y:390 },
    { id:'kafka',     label:'Kafka',       cluster:3, x:610, y:200 },
    { id:'analytics', label:'Analytics',   cluster:3, x:660, y:340 },

    /* Infra cluster — far right */
    { id:'k8s',       label:'K8s',         cluster:4, x:750, y:240 },
    { id:'monitor',   label:'Monitor',     cluster:4, x:760, y:370 },
    { id:'cicd',      label:'CI/CD',       cluster:4, x:810, y:160 },

    /* Auth cluster — top-centre */
    { id:'auth-svc',  label:'Auth Svc',    cluster:5, x:450, y:135 },
    { id:'oauth',     label:'OAuth',       cluster:5, x:560, y:130 },
  ];

  var edges = [
    /* Frontend → Backend */
    { a:'web-app',   b:'cdn'       },
    { a:'mobile',    b:'cdn'       },
    { a:'cdn',       b:'api-gw'    },
    { a:'web-app',   b:'api-gw'    },

    /* Backend internal */
    { a:'api-gw',    b:'user-svc'  },
    { a:'api-gw',    b:'order-svc' },
    { a:'order-svc', b:'notify'    },
    { a:'user-svc',  b:'notify'    },

    /* Backend → Data */
    { a:'user-svc',  b:'postgres'  },
    { a:'order-svc', b:'postgres'  },
    { a:'user-svc',  b:'redis'     },
    { a:'order-svc', b:'redis'     },
    { a:'notify',    b:'kafka'     },
    { a:'api-gw',    b:'kafka'     },
    { a:'kafka',     b:'analytics' },
    { a:'postgres',  b:'analytics' },

    /* Auth */
    { a:'auth-svc',  b:'api-gw'    },
    { a:'auth-svc',  b:'oauth'     },
    { a:'oauth',     b:'k8s'       },

    /* Infra */
    { a:'k8s',       b:'api-gw'    },
    { a:'k8s',       b:'postgres'  },
    { a:'k8s',       b:'monitor'   },
    { a:'cicd',      b:'k8s'       },
    { a:'monitor',   b:'analytics' },
  ];

  /* ── BUILD LOOKUP + DEGREE ──────────────────────────────────────────── */
  var byId = {};
  nodes.forEach(function(n) { byId[n.id] = n; n.neighbours = []; n.edgeEls = []; });

  edges.forEach(function(e) {
    byId[e.a].neighbours.push(e.b);
    byId[e.b].neighbours.push(e.a);
  });

  /* radius encodes degree: r = 11 + clamp(degree-1, 0, 5) * 2.2 */
  nodes.forEach(function(n) {
    var deg = n.neighbours.length;
    n.r = 11 + Math.min(deg - 1, 5) * 2.2;
  });

  /* ── PLOT BOUNDS ────────────────────────────────────────────────────── */
  var plotL = 68, plotR = 850, plotT = 100, plotB = 500;

  /* ── STAGGER ────────────────────────────────────────────────────────── */
  var totalEls = edges.length + nodes.length;
  var stagger  = Math.min(0.25, 1.0 / totalEls);
  var lastDelay = (totalEls - 1) * stagger;
  var readyDelay = (lastDelay + 0.8 + 0.1) * 1000;

  /* ── BUILD EDGES ────────────────────────────────────────────────────── */
  edges.forEach(function(e, i) {
    var na = byId[e.a], nb = byId[e.b];
    /* edge cluster = source cluster color for visual coherence */
    var cls = 'edge stroke-' + na.cluster;

    var line = document.createElementNS('http://www.w3.org/2000/svg', 'line');
    line.setAttribute('x1', na.x); line.setAttribute('y1', na.y);
    line.setAttribute('x2', nb.x); line.setAttribute('y2', nb.y);
    line.setAttribute('class', cls);
    line.setAttribute('data-a', e.a);
    line.setAttribute('data-b', e.b);
    line.style.animationDelay = (i * stagger) + 's';
    edgeLayer.appendChild(line);

    /* back-reference from nodes for hover */
    na.edgeEls.push(line);
    nb.edgeEls.push(line);
  });

  /* ── BUILD NODES ────────────────────────────────────────────────────── */
  nodes.forEach(function(n, i) {
    var ng = document.createElementNS('http://www.w3.org/2000/svg', 'g');
    ng.setAttribute('class', 'node-g');
    ng.setAttribute('id', 'ng-' + n.id);
    ng.style.animationDelay = (edges.length * stagger + i * stagger) + 's';

    /* filled circle */
    var circle = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
    circle.setAttribute('cx', n.x); circle.setAttribute('cy', n.y);
    circle.setAttribute('r',  n.r);
    circle.setAttribute('class', 'node-circle series-' + n.cluster + ' stroke-' + n.cluster);

    /* label: place below node if room, above if near bottom */
    var labelY = (n.y + n.r + 13 <= plotB) ? n.y + n.r + 11 : n.y - n.r - 4;
    var lbl = document.createElementNS('http://www.w3.org/2000/svg', 'text');
    lbl.setAttribute('x', n.x); lbl.setAttribute('y', labelY);
    lbl.setAttribute('text-anchor', 'middle');
    lbl.setAttribute('class', 'node-lbl');
    lbl.textContent = n.label;

    ng.appendChild(circle);
    ng.appendChild(lbl);
    nodeLayer.appendChild(ng);
    n._ng = ng;
  });

  /* ── §3 A1 ANIMATION — animationend per element, .visible provides resting opacity ── */
  Array.prototype.forEach.call(edgeLayer.querySelectorAll('.edge'), function(el) {
    el.style.animation = 'edgeFadeIn 0.8s ease-out ' + el.style.animationDelay;
    el.addEventListener('animationend', function() {
      el.style.animation = 'none';
      el.classList.add('visible');
    }, { once: true });
  });
  Array.prototype.forEach.call(nodeLayer.querySelectorAll('.node-g'), function(el) {
    el.style.animation = 'nodeFadeIn 0.8s ease-out ' + el.style.animationDelay;
    el.addEventListener('animationend', function() {
      el.style.animation = 'none';
      el.classList.add('visible');
    }, { once: true });
  });

  setTimeout(function() {
    dataLayerEl.classList.add('ready');
  }, readyDelay);

  /* ── §5 TOOLTIP ─────────────────────────────────────────────────────── */
  var tip    = document.getElementById('tip');
  var tipBg  = document.getElementById('tip-bg');
  var tipBdr = document.getElementById('tip-bdr');
  var tipTip = document.getElementById('tip-tip');
  var tipVal = document.getElementById('tip-val');
  var tipLbl = document.getElementById('tip-lbl');

  function showTip(cx, cy, nodeR, valTxt, lblTxt) {
    tipVal.textContent = valTxt;
    tipLbl.textContent = lblTxt;
    var pad = 20, bh = 38, rx = 9, tw = 8, tail = 10;
    var hw  = Math.max(tipVal.getBBox().width, tipLbl.getBBox().width) / 2 + pad / 2;
    var tx  = Math.max(hw + 8, Math.min(cx, plotR - hw - 8));
    /* anchor at top of node circle */
    var anchorY = cy - nodeR;
    var above = (anchorY - tail - bh - 4) >= plotT;
    var bT, bB;
    if (above) { bB = anchorY - tail; bT = bB - bh; }
    else        { bT = anchorY + tail + nodeR * 2; bB = bT + bh; }

    tipBg.setAttribute('x', tx - hw); tipBg.setAttribute('y', bT);
    tipBg.setAttribute('width', hw * 2); tipBg.setAttribute('height', bh);

    var tipAnchorY = above ? anchorY : anchorY + nodeR * 2;
    if (above) {
      tipBdr.setAttribute('d',
        'M'+(tx+tw)+','+bB+' L'+(tx+hw-rx)+','+bB+' Q'+(tx+hw)+','+bB+' '+(tx+hw)+','+(bB-rx)+
        ' L'+(tx+hw)+','+(bT+rx)+' Q'+(tx+hw)+','+bT+' '+(tx+hw-rx)+','+bT+
        ' L'+(tx-hw+rx)+','+bT+' Q'+(tx-hw)+','+bT+' '+(tx-hw)+','+(bT+rx)+
        ' L'+(tx-hw)+','+(bB-rx)+' Q'+(tx-hw)+','+bB+' '+(tx-hw+rx)+','+bB+' L'+(tx-tw)+','+bB);
      tipTip.setAttribute('d', 'M'+(tx-tw)+','+bB+' L'+tx+','+(tipAnchorY-2)+' L'+(tx+tw)+','+bB);
    } else {
      tipBdr.setAttribute('d',
        'M'+(tx-tw)+','+bT+' L'+(tx-hw+rx)+','+bT+' Q'+(tx-hw)+','+bT+' '+(tx-hw)+','+(bT+rx)+
        ' L'+(tx-hw)+','+(bB-rx)+' Q'+(tx-hw)+','+bB+' '+(tx-hw+rx)+','+bB+
        ' L'+(tx+hw-rx)+','+bB+' Q'+(tx+hw)+','+bB+' '+(tx+hw)+','+(bB-rx)+
        ' L'+(tx+hw)+','+(bT+rx)+' Q'+(tx+hw)+','+bT+' '+(tx+hw-rx)+','+bT+' L'+(tx+tw)+','+bT);
      tipTip.setAttribute('d', 'M'+(tx+tw)+','+bT+' L'+tx+','+(tipAnchorY+2)+' L'+(tx-tw)+','+bT);
    }

    tipVal.setAttribute('x', tx); tipVal.setAttribute('y', bT + bh * 0.32);
    tipLbl.setAttribute('x', tx); tipLbl.setAttribute('y', bT + bh * 0.72);
    tip.style.opacity = '1';
  }

  function hideTip() {
    tip.style.opacity = '';
  }

  /* ── §4 HOVER ────────────────────────────────────────────────────────
     Nodes have clear gaps → element-level mouseleave.
     On hover: highlight hovered node + all neighbours + connecting edges.
     Everything else dims.                                                */
  var allNodeGs = Array.prototype.slice.call(nodeLayer.querySelectorAll('.node-g'));
  var allEdges  = Array.prototype.slice.call(edgeLayer.querySelectorAll('.edge'));
  var clusterNames = ['','Frontend','Backend','Data','Infra','Auth'];

  nodes.forEach(function(n) {
    var ng = n._ng;
    ng.addEventListener('mouseenter', function() {
      if (!dataLayerEl.classList.contains('ready')) return;

      /* clear all stale classes */
      allNodeGs.forEach(function(el) { el.classList.remove('hovered'); el.classList.remove('connected'); });
      allEdges.forEach(function(el)  { el.classList.remove('connected'); });

      dataLayerEl.classList.add('hovering');
      ng.classList.add('hovered');

      /* mark neighbours */
      n.neighbours.forEach(function(nid) {
        var nng = document.getElementById('ng-' + nid);
        if (nng) nng.classList.add('connected');
      });

      /* mark connecting edges */
      n.edgeEls.forEach(function(el) { el.classList.add('connected'); });

      var deg = n.neighbours.length;
      showTip(n.x, n.y, n.r,
        n.label,
        clusterNames[n.cluster] + ' \u00b7 ' + deg + ' connection' + (deg !== 1 ? 's' : ''));
    });

    ng.addEventListener('mouseleave', function() {
      allNodeGs.forEach(function(el) { el.classList.remove('hovered'); el.classList.remove('connected'); });
      allEdges.forEach(function(el)  { el.classList.remove('connected'); });
      dataLayerEl.classList.remove('hovering');
      hideTip();
    });
  });

  /* ── PRINT TOGGLE ────────────────────────────────────────────────────── */

  /* ── §2 DARK MODE ────────────────────────────────────────────────────── */
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
